70	library	IEEE;
71	use			IEEE.std_logic_1164.all;
72	use			IEEE.numeric_std.all;
73	
74	library PoC;
75	use			PoC.config.all;
76	use			PoC.utils.all;
77	use			PoC.strings.all;
78	use			PoC.vectors.all;
79	use			PoC.mem.all;
80	
81	
82	entity ocram_tdp is
83		generic (
84			A_BITS		: positive;															-- number of address bits
85			D_BITS		: positive;															-- number of data bits
86			FILENAME	: string		:= ""												-- file-name for RAM initialization
87		);
88		port (
89			clk1 : in	std_logic;															-- clock for 1st port
90			clk2 : in	std_logic;															-- clock for 2nd port
91			ce1	: in	std_logic;															-- clock-enable for 1st port
92			ce2	: in	std_logic;															-- clock-enable for 2nd port
93			we1	: in	std_logic;															-- write-enable for 1st port
94			we2	: in	std_logic;															-- write-enable for 2nd port
95			a1	 : in	unsigned(A_BITS-1 downto 0);						-- address for 1st port
96			a2	 : in	unsigned(A_BITS-1 downto 0);						-- address for 2nd port
97			d1	 : in	std_logic_vector(D_BITS-1 downto 0);		-- write-data for 1st port
98			d2	 : in	std_logic_vector(D_BITS-1 downto 0);		-- write-data for 2nd port
99			q1	 : out std_logic_vector(D_BITS-1 downto 0);		-- read-data from 1st port
100			q2	 : out std_logic_vector(D_BITS-1 downto 0) 		-- read-data from 2nd port
101		);
102	end entity;
103	
104	
105	architecture rtl of ocram_tdp is
106		constant DEPTH : positive := 2**A_BITS;
107	
108	begin
109		gInfer : if not SIMULATION and ((VENDOR = VENDOR_LATTICE) or (VENDOR = VENDOR_XILINX)) generate
110			-- RAM can be inferred correctly only if '-use_new_parser yes' is enabled in XST options
111			subtype word_t	is std_logic_vector(D_BITS - 1 downto 0);
112			type		ram_t		is array(0 to DEPTH - 1) of word_t;
113	
114			-- Compute the initialization of a RAM array, if specified, from the passed file.
115			impure function ocram_InitMemory(FilePath : string) return ram_t is
116				variable Memory		: T_SLM(DEPTH - 1 downto 0, word_t'range);
117				variable res			: ram_t;
118			begin
119				if str_length(FilePath) = 0 then
120	        -- shortcut required by Vivado
121					return (others => (others => ite(SIMULATION, 'U', '0')));
122				elsif mem_FileExtension(FilePath) = "mem" then
123					Memory	:= mem_ReadMemoryFile(FilePath, DEPTH, word_t'length, MEM_FILEFORMAT_XILINX_MEM, MEM_CONTENT_HEX);
124				else
125					Memory	:= mem_ReadMemoryFile(FilePath, DEPTH, word_t'length, MEM_FILEFORMAT_INTEL_HEX, MEM_CONTENT_HEX);
126				end if;
127	
128				for i in Memory'range(1) loop
129					for j in word_t'range loop
130						res(i)(j)		:= Memory(i, j);
131					end loop;
132				end loop;
133				return  res;
134			end function;
135	
136			signal ram			: ram_t		:= ocram_InitMemory(FILENAME);
137			signal a1_reg		: unsigned(A_BITS-1 downto 0);
138			signal a2_reg		: unsigned(A_BITS-1 downto 0);
139	
140		begin
141	
142			process (clk1, clk2)
143			begin	-- process
144				if rising_edge(clk1) then
145					if ce1 = '1' then
146						if we1 = '1' then
147							ram(to_integer(a1)) <= d1;
148						end if;
149	
150						a1_reg <= a1;
151					end if;
152				end if;
153	
154				if rising_edge(clk2) then
155					if ce2 = '1' then
156						if we2 = '1' then
157							ram(to_integer(a2)) <= d2;
158						end if;
159	
160						a2_reg <= a2;
161					end if;
162				end if;
163			end process;
164	
165			q1 <= (others => 'X') when SIMULATION and is_x(std_logic_vector(a1_reg)) else
166						ram(to_integer(a1_reg));		-- returns new data
167			q2 <= (others => 'X') when SIMULATION and is_x(std_logic_vector(a2_reg)) else
168						ram(to_integer(a2_reg));		-- returns new data
169		end generate gInfer;
170	
171		gAltera: if not SIMULATION and (VENDOR = VENDOR_ALTERA) generate
172			component ocram_tdp_altera
173				generic (
174					A_BITS		: positive;
175					D_BITS		: positive;
176					FILENAME	: string		:= ""
177				);
178				port (
179					clk1 : in	std_logic;
180					clk2 : in	std_logic;
