151				if not Good then
152					report "Error while reading memory file '" & FileName & "'." severity FAILURE;
153					return Result;
154				end if;
155				for j in 0 to BitsPerMemoryLine - 1 loop
156					Result(i, j) := TempWord(j);
157				end loop;
158			end loop;
159			return  Result;
